// ============================================================================
// Tests: findNearestEarlierStage — graceful fallback for missing fromStage
// ============================================================================

describe('findNearestEarlierStage', () => {
  const LIGHTWEIGHT = ['taskify', 'clarify', 'architect', 'build', 'commit', 'verify', 'pr']
  const FULL_PIPELINE = [
    'taskify',
    'gap',
    'clarify',
    'architect',
    'plan-gap',
    'build',
    'commit',
    'verify',
    'pr',
  ]

  it('gap missing from lightweight pipeline falls back to taskify', () => {
    // gap doesn't exist in lightweight, taskify is the nearest earlier stage
    const result = findNearestEarlierStage('gap', LIGHTWEIGHT)
    expect(result).toBe('taskify')
  })

  it('plan-gap missing from lightweight falls back to architect', () => {
    // plan-gap doesn't exist in lightweight, architect is the nearest earlier stage
    const result = findNearestEarlierStage('plan-gap', LIGHTWEIGHT)
    expect(result).toBe('architect')
  })

  it('unknown stage falls back to first pipeline stage', () => {
    // Unknown stage not in ALL_STAGES → returns first stage in pipeline
    const result = findNearestEarlierStage('nonexistent', LIGHTWEIGHT)
    expect(result).toBe('taskify')
  })

  it('stage exists in pipeline returns nearest earlier stage', () => {
    // build exists but we want the nearest earlier stage (architect)
    const result = findNearestEarlierStage('build', FULL_PIPELINE)
    expect(result).toBe('architect')
  })

  it('no earlier stage exists returns first pipeline stage', () => {
    // taskify is first in ALL_STAGES, nothing before it
    const result = findNearestEarlierStage('taskify', FULL_PIPELINE)
    expect(result).toBe('taskify')
  })

  it('gap exists in full pipeline returns gap itself', () => {
    // gap exists in pipeline - should still find nearest earlier (none before it in this pipeline)
    const result = findNearestEarlierStage('gap', FULL_PIPELINE)
    expect(result).toBe('taskify')
  })
})

